def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np

    pts_all = np.asarray(points, dtype=float)
    if pts_all.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N_all, D = pts_all.shape
    if k <= 0:
        return np.zeros((0, D))
    if k >= N_all:
        return pts_all.copy()

    # reference point
    if reference_point is None:
        reference_point = pts_all.max(axis=0) * 1.1
    ref = np.asarray(reference_point, dtype=float)
    if ref.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # ensure ref is slightly worse than best observed
    pts_min_all = pts_all.min(axis=0)
    eps = 1e-9
    ref = ref.copy()
    mask_too_small = ref <= pts_min_all + eps
    if np.any(mask_too_small):
        ref[mask_too_small] = pts_min_all[mask_too_small] + 1e-6 + 0.1 * np.abs(pts_min_all[mask_too_small]) + eps

    # fast nondominated pruning (minimization)
    def nondominated_indices(a):
        idxs = np.lexsort(a.T[::-1])
        front = []
        for i in idxs:
            p = a[i]
            if not front:
                front.append(i)
                continue
            front_pts = a[np.array(front)]
            if np.any((front_pts <= p).all(axis=1)):
                continue
            dominated_mask = (p <= front_pts).all(axis=1) & ((p < front_pts).any(axis=1))
            if np.any(dominated_mask):
                keep = np.where(~dominated_mask)[0]
                front = list(np.array(front)[keep])
            front.append(i)
        return np.array(front, dtype=int)

    nd_idx = nondominated_indices(pts_all)
    if nd_idx.size == 0:
        box_vol = np.prod(np.maximum(0.0, ref - pts_all), axis=1)
        idx = np.argsort(-box_vol)[:k]
        return pts_all[idx].copy()

    if nd_idx.size < N_all:
        pts = pts_all[nd_idx]
    else:
        pts = pts_all.copy()
    N = pts.shape[0]
    if N <= k:
        if nd_idx.size < N_all:
            return pts_all[nd_idx].copy()
        return pts.copy()

    # Monte Carlo sample size: modest, adaptive to k
    M = int(min(5000, max(800, 120 * k)))
    rng = np.random.RandomState(0)

    low = pts.min(axis=0)
    high = ref.copy()
    zero_range = (high - low) <= 0
    if np.any(zero_range):
        high = high.copy()
        low = low.copy()
        high[zero_range] = low[zero_range] + 1e-6 + 0.1 * (np.abs(low[zero_range]) + 1.0)

    samples = low + rng.rand(M, D) * (high - low)

    # Build dominated boolean matrix in blocks to cap memory
    max_bool_entries = 80_000_000
    dominated = np.zeros((N, M), dtype=bool)
    if N * M <= max_bool_entries:
        dominated = (pts[:, None, :] <= samples[None, :, :]).all(axis=2)
    else:
        block = int(max(1, max_bool_entries // M))
        i = 0
        while i < N:
            j = min(N, i + block)
            dominated[i:j, :] = (pts[i:j, None, :] <= samples[None, :, :]).all(axis=2)
            i = j

    sample_covered_any = dominated.any(axis=0)
    if not np.any(sample_covered_any):
        # fallback: choose by box-volume
        box_vol = np.prod(np.maximum(0.0, high - pts), axis=1)
        idx = np.argsort(-box_vol)[:k]
        if nd_idx.size < N_all:
            return pts_all[nd_idx[idx]].copy()
        return pts[idx].copy()

    rel_idx = np.where(sample_covered_any)[0]
    dominated = dominated[:, rel_idx]
    M_rel = dominated.shape[1]

    box_volumes = np.prod(np.maximum(0.0, high - pts), axis=1)
    counts = dominated.sum(axis=1).astype(int)

    selected = []
    selected_mask = np.zeros(N, dtype=bool)
    covered = np.zeros(M_rel, dtype=bool)

    # try exact HV for tiny tie resolution
    try:
        import pygmo as pg  # type: ignore
        hv_available = True
    except Exception:
        hv_available = False

    def exact_hv_of_set(points_set):
        if points_set.size == 0:
            return 0.0
        try:
            hv = pg.hypervolume(points_set)
            return hv.compute(ref)
        except Exception:
            return 0.0

    tie_shortlist = 5

    for _ in range(k):
        remaining = np.where(~selected_mask)[0]
        if remaining.size == 0:
            break

        not_covered = ~covered
        if not np.any(not_covered):
            # choose by box volume among remaining
            order = np.argsort(-box_volumes[remaining])[: (k - len(selected))]
            for r in order:
                idx = remaining[r]
                selected.append(int(idx))
                selected_mask[idx] = True
            break

        marg = counts[remaining]
        max_count = int(marg.max())
        if max_count == 0:
            # sampling granularity: pick top box-volumes and update
            order = np.argsort(-box_volumes[remaining])[: (k - len(selected))]
            for r in order:
                idx = remaining[r]
                selected.append(int(idx))
                selected_mask[idx] = True
                newly = dominated[idx] & (~covered)
                if newly.any():
                    covered |= newly
                    counts -= (dominated[:, newly].sum(axis=1)).astype(int)
                    counts = np.maximum(counts, 0)
            break

        cand_pos = np.where(marg == max_count)[0]
        cand_indices = remaining[cand_pos]
        # shortlist by box volume if many candidates
        if cand_indices.size > tie_shortlist:
            order = np.argsort(-box_volumes[cand_indices])[:tie_shortlist]
            cand_indices = cand_indices[order]

        chosen = int(cand_indices[0])
        if hv_available and cand_indices.size > 1:
            # compute exact marginal hv on small shortlist
            current_set = pts[np.array(selected)] if len(selected) > 0 else np.zeros((0, D))
            hv_current = exact_hv_of_set(current_set)
            best = None
            best_delta = -1.0
            for c in cand_indices:
                if current_set.size == 0:
                    delta = exact_hv_of_set(pts[[c], :])
                else:
                    new_set = np.vstack([current_set, pts[c]])
                    hv_new = exact_hv_of_set(new_set)
                    delta = hv_new - hv_current
                if delta > best_delta:
                    best_delta = delta
                    best = int(c)
            if best is not None:
                chosen = best
        else:
            if cand_indices.size > 1:
                tv = box_volumes[cand_indices]
                chosen = int(cand_indices[np.argmax(tv)])

        # select chosen
        selected.append(int(chosen))
        selected_mask[chosen] = True
        newly_covered = dominated[chosen] & (~covered)
        if newly_covered.any():
            covered |= newly_covered
            counts -= (dominated[:, newly_covered].sum(axis=1)).astype(int)
            counts = np.maximum(counts, 0)

        # early fill if all covered
        if covered.all():
            rem_left = np.where(~selected_mask)[0]
            if rem_left.size > 0:
                rem_needed = k - len(selected)
                if rem_needed > 0:
                    order = np.argsort(-box_volumes[rem_left])[:rem_needed]
                    for r in order:
                        sel_idx = rem_left[r]
                        selected.append(int(sel_idx))
                        selected_mask[sel_idx] = True
            break

    selected = np.array(selected, dtype=int)[:k]

    # map back to original indices if pruned
    if nd_idx.size < N_all:
        return pts_all[nd_idx[selected]].copy()
    return pts[selected].copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np, heapq

    # ---------- basic checks ----------
    pts_all = np.asarray(points, dtype=float)
    if pts_all.ndim != 2:
        raise ValueError("points must be a 2‑D array")
    N_all, D = pts_all.shape
    if k <= 0:
        return np.empty((0, D))
    if k >= N_all:
        return pts_all.copy()

    # ---------- reference ----------
    if reference_point is None:
        reference_point = pts_all.max(axis=0) * 1.1
    ref = np.asarray(reference_point, dtype=float)
    if ref.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # ---------- 1) prune dominated (minimisation) ----------
    def nondominated_idx(arr):
        order = np.lexsort(arr.T[::-1])
        front = []
        for i in order:
            p = arr[i]
            if not front:
                front.append(i)
                continue
            front_pts = arr[np.array(front)]
            if np.any((front_pts <= p).all(axis=1)):
                continue
            dom = (p <= front_pts).all(axis=1) & (p < front_pts).any(axis=1)
            if np.any(dom):
                keep = np.where(~dom)[0]
                front = list(np.array(front)[keep])
            front.append(i)
        return np.array(front, dtype=int)

    nd_idx = nondominated_idx(pts_all)
    if nd_idx.size < N_all:
        pts = pts_all[nd_idx]
        orig_idx = nd_idx.copy()
    else:
        pts = pts_all
        orig_idx = np.arange(N_all, dtype=int)

    N = pts.shape[0]
    if N <= k:
        return pts.copy()

    # ---------- 2) MC samples ----------
    low = pts.min(axis=0)
    span = ref - low
    span[span <= 0] = 1e-12
    M = int(min(8000, max(1500, 200 * k, 800 * D)))      # adaptive sample count
    rng = np.random.default_rng(0)
    samples = rng.random((M, D)) * span + low

    # ---------- 3) domination masks (block‑wise) ----------
    max_bool = int(8e7)                # ~10 MiB of bool entries per block
    block = max(1, int(max_bool // M))
    masks = np.empty((N, M), dtype=bool)
    for s in range(0, N, block):
        e = min(N, s + block)
        chunk = pts[s:e]                # (b, D)
        masks[s:e] = np.all(chunk[:, None, :] <= samples[None, :, :], axis=2)

    init_gain = masks.sum(axis=1).astype(np.int32)

    # if no sample covered at all -> fallback to box‑volume greedy
    if init_gain.sum() == 0:
        box_vol = np.prod(np.maximum(0.0, ref - pts), axis=1)
        chosen = np.argsort(-box_vol)[:k]
        return pts_all[orig_idx[chosen]].copy()

    # ---------- 4) optional sparse index lists ----------
    avg_dom = init_gain.mean()
    use_lists = avg_dom < (M / 4)
    if use_lists:
        idx_lists = [np.nonzero(masks[i])[0] if init_gain[i] else np.empty(0, int)
                     for i in range(N)]
    else:
        idx_lists = None

    # ---------- 5) lazy greedy selection ----------
    heap = [(-g, i) for i, g in enumerate(init_gain)]
    heapq.heapify(heap)
    selected = []
    uncovered = np.ones(M, dtype=bool)

    while len(selected) < k and heap:
        neg_g, i = heapq.heappop(heap)
        est = -neg_g
        if est == 0:
            break
        # true marginal gain
        if use_lists:
            cand = idx_lists[i]
            true_gain = int(np.count_nonzero(uncovered[cand])) if cand.size else 0
        else:
            true_gain = int(np.count_nonzero(masks[i] & uncovered))
        if true_gain == 0:
            continue
        if true_gain != est:
            heapq.heappush(heap, (-true_gain, i))
            continue
        # accept
        selected.append(i)
        if use_lists:
            to_cov = idx_lists[i]
            if to_cov.size:
                uncovered[to_cov] = False
        else:
            newly = masks[i] & uncovered
            if newly.any():
                uncovered[newly] = False
        if not uncovered.any():
            break

    # fill missing slots with box‑volume if needed
    if len(selected) < k:
        remaining = np.setdiff1d(np.arange(N), selected, assume_unique=True)
        box_vol = np.prod(np.maximum(0.0, ref - pts), axis=1)
        extra = remaining[np.argsort(-box_vol[remaining])[:k - len(selected)]]
        selected.extend(extra.tolist())

    selected = np.array(selected, dtype=int)[:k]

    # ---------- 6) small shortlist & bounded exact refinement ----------
    not_sel = np.setdiff1d(np.arange(N), selected, assume_unique=True)
    if not_sel.size:
        if use_lists:
            marginal = np.array([int(np.count_nonzero(uncovered[idx_lists[i]]))
                                 for i in not_sel], dtype=int)
        else:
            marginal = (masks[not_sel] & uncovered).sum(axis=1)
        order = np.argsort(-marginal)
        extra = not_sel[order][:min(2 * k, not_sel.size)]
        shortlist_idx = np.unique(np.concatenate([selected, extra]))
    else:
        shortlist_idx = selected.copy()

    shortlist = pts[shortlist_idx]
    sel_pos = [int(np.where(shortlist_idx == i)[0][0]) for i in selected]

    # optional exact swap refinement (very limited)
    try:
        import pygmo as pg
        have_pg = True
    except Exception:
        have_pg = False

    if have_pg and shortlist.shape[0] > k and shortlist.shape[0] <= 150:
        def hv(arr):
            if arr.size == 0:
                return 0.0
            return pg.hypervolume(arr).compute(ref)

        cur = np.array(sel_pos, dtype=int)
        best_hv = hv(shortlist[cur])
        improved = True
        max_iter = 20
        it = 0
        while improved and it < max_iter:
            improved = False
            it += 1
            for p in range(len(cur)):
                for cand in range(shortlist.shape[0]):
                    if cand in cur:
                        continue
                    trial = cur.copy()
                    trial[p] = cand
                    val = hv(shortlist[trial])
                    if val > best_hv + 1e-12:
                        best_hv = val
                        cur = trial
                        improved = True
                        break
                if improved:
                    break
        refined_idx = shortlist_idx[cur]
    else:
        refined_idx = shortlist_idx[np.array(sel_pos, dtype=int)]

    final_idx = refined_idx[:k]
    return pts_all[orig_idx[final_idx]].copy()
